mapper.select:
SELECT *
FROM esg.tb_orgn_chart toc
WHERE toc.chart_id = #{searchText}

mapper.update:
UPDATE esg.tb_orgn_chart
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE chart_id = #{chartId}

UPDATE esg.tb_orgn_chart SET confirm_yn = #{confirmYn},
confirm_dt = now(),
updated_at = now(), updated_by = #{updatedBy} WHERE chart_id = #{chartId}

mapper.delete:
UPDATE esg.tb_orgn_info
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE orgn_id = #{orgnId}

mapper.select:
SELECT tom.* , tom.orgn_id as id , toi.orgn_nm as nm FROM esg.tb_orgn_map tom LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = tom.orgn_id WHERE 1=1 AND tom.target_id IN
#{id}
AND tom.target_type = #{targetType} AND tom.use_yn = 'Y' ORDER BY tom.orgn_id ASC

mapper.update:
UPDATE esg.tb_orgn_map
SET
    orgn_id = #{id},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE target_id = #{targetId}
  AND target_type = #{targetType}

UPDATE esg.tb_orgn_map
SET
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE target_id = #{targetId}
  AND target_type = #{targetType}
  AND orgn_id = #{id}

mapper.delete:
UPDATE esg.tb_orgn_map
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE target_id = #{targetId}
  AND target_type = #{targetType}
  AND use_yn = 'Y'
